// ── Core Search ───────────────────────────────────
async function runSearch() {
  showLoading();
  try {
    const key      = getKey();
    const region   = document.getElementById('fRegion').value;
    const catId    = document.getElementById('fCategory').value;
    const query    = document.getElementById('searchQuery').value.trim();
    const hasQuery = query.length > 0;

    let videos = [];
    let mode   = '';

    if (!hasQuery) {
      // ── 검색어 없음: mostPopular (지역 인기 영상) ──
      mode = '지역 인기';
      const params = new URLSearchParams({
        part: 'snippet,statistics', chart: 'mostPopular',
        regionCode: region, maxResults: 50, key,
      });
      if (catId) params.set('videoCategoryId', catId);

      const data = await fetchJson('https://www.googleapis.com/youtube/v3/videos?' + params);
      if (data.error) throw new Error(data.error.message);

      const channelIds = [...new Set((data.items||[]).map(v => v.snippet.channelId))].join(',');
      const chData = await fetchJson(
        `https://www.googleapis.com/youtube/v3/channels?part=statistics&id=${channelIds}&key=${key}`
      );
      if (chData.error) throw new Error(chData.error.message);
      const chMap = Object.fromEntries((chData.items||[]).map(c => [c.id, c]));

      videos = (data.items||[]).map(v => makeVideo(v.id, v.snippet, v.statistics, chMap));

    } else {
      // ── 검색어 있음: search.list → videos.list → channels.list ──
      mode = `"${query}" 검색`;
      const sp = new URLSearchParams({
        part: 'snippet', type: 'video', maxResults: 50,
        order: document.getElementById('fOrder').value,
        regionCode: region,
        videoDuration: document.getElementById('fDuration').value,
        videoDefinition: document.getElementById('fDefinition').value,
        safeSearch: document.getElementById('fSafe').value,
        q: query, key,
      });
      if (catId) sp.set('videoCategoryId', catId);
      const lang = document.getElementById('fLang').value;
      if (lang) sp.set('relevanceLanguage', lang);
      const after = getPeriodISO(state.period);
      if (after) sp.set('publishedAfter', after);

      const searchData = await fetchJson('https://www.googleapis.com/youtube/v3/search?' + sp);
      if (searchData.error) throw new Error(searchData.error.message);

      const items = (searchData.items||[]).filter(i => i.id?.videoId);
      if (items.length === 0) {
        renderEmpty();
        updateInfo(mode, 0);
        return;
      }

      const videoIds   = items.map(i => i.id.videoId).join(',');
      const channelIds = [...new Set(items.map(i => i.snippet.channelId))].join(',');

      const [vData, chData] = await Promise.all([
        fetchJson(`https://www.googleapis.com/youtube/v3/videos?part=statistics,snippet&id=${videoIds}&key=${key}`),
        fetchJson(`https://www.googleapis.com/youtube/v3/channels?part=statistics&id=${channelIds}&key=${key}`),
      ]);
      if (vData.error)  throw new Error(vData.error.message);
      if (chData.error) throw new Error(chData.error.message);

      const vMap  = Object.fromEntries((vData.items||[]).map(v => [v.id, v]));
      const chMap = Object.fromEntries((chData.items||[]).map(c => [c.id, c]));

      videos = items.reduce((acc, item) => {
        const v = vMap[item.id.videoId];
        if (v) acc.push(makeVideo(v.id, v.snippet || item.snippet, v.statistics, chMap));
        return acc;
      }, []);
    }

    // 효율성 내림차순 정렬
    videos.sort((a, b) => b.eff - a.eff);
    state.allVideos = videos;

    updateInfo(mode, videos.length);
    renderThreeCols();

  } catch (err) {
    document.getElementById('threeCol').innerHTML =
      '<div class="loading-box" style="color:#555;"></div>';
    showError('오류: ' + err.message);
  }
}

