/* ── Active Filter Chips ── */
.active-filters {
  display: flex; flex-wrap: wrap; gap: 5px;
  padding: 5px 0 2px;
  min-height: 0;
}
.active-filters:empty { display: none; }

.filter-chip {
  display: inline-flex; align-items: center; gap: 4px;
  background: #1e2a1e; border: 1px solid #2d5a2d;
  color: #6dbb6d; padding: 2px 8px 2px 8px;
  border-radius: 12px; font-size: 11px; cursor: default;
}
.filter-chip.red   { background: #2a1e1e; border-color: #5a2d2d; color: #bb6d6d; }
.filter-chip.blue  { background: #1e1e2a; border-color: #2d2d5a; color: #6d6dbb; }
.filter-chip.gray  { background: #1e1e1e; border-color: #3a3a3a; color: #888; }

.chip-del {
  background: none; border: none; color: inherit;
  cursor: pointer; font-size: 13px; line-height: 1;
  padding: 0; opacity: 0.7; margin-left: 1px;
}
.chip-del:hover { opacity: 1; }

/* ── Advanced Filters ── */
.filter-advanced {
  background: #141414; border-bottom: 1px solid #2a2a2a;
  overflow: hidden; max-height: 0;
  transition: max-height 0.2s ease, padding 0.2s ease; padding: 0 16px;
}
.filter-advanced.open { max-height: 60px; padding: 7px 16px; }

