function makeExcludeAddBtn() {
  // 제외 가능한 카테고리 목록 (현재 미제외 항목만)
  const available = Object.entries(CAT).filter(([id]) => !filters.excludedCats.has(id));

  const wrap = document.createElement('div');
  wrap.className = 'exclude-add';
  wrap.innerHTML = `
    <span>+ 카테고리 제외</span>
    <div class="exclude-dropdown" id="excludeDropdown">
      ${available.length === 0
        ? '<div class="exclude-dropdown-item disabled">모두 제외 중</div>'
        : available.map(([id, name]) =>
            `<div class="exclude-dropdown-item" data-id="${esc(id)}">${esc(name)}</div>`
          ).join('')
      }
    </div>
  `;

  wrap.addEventListener('click', (e) => {
    const item = e.target.closest('.exclude-dropdown-item');
    if (item && item.dataset.id) {
      filters.excludedCats.add(item.dataset.id);
      doSearch();
      return;
    }
    // 드롭다운 토글
    const dd = wrap.querySelector('.exclude-dropdown');
    const isOpen = dd.classList.toggle('open');
    if (isOpen) {
      // 외부 클릭 시 닫기
      setTimeout(() => {
        document.addEventListener('click', function closer(ev) {
          if (!wrap.contains(ev.target)) {
            dd.classList.remove('open');
            document.removeEventListener('click', closer);
          }
        });
      }, 0);
    }
    e.stopPropagation();
  });

  return wrap;
}

function makeChip(label, color, onRemove) {
  const chip = document.createElement('span');
  chip.className = `filter-chip${color ? ' ' + color : ''}`;
  chip.innerHTML = `${esc(label)}<button class="chip-del" title="제거">×</button>`;
  chip.querySelector('.chip-del').addEventListener('click', onRemove);
  return chip;
}

