if (!query) {
  // ── 검색어 없음: 다중 카테고리 병렬 검색 ──
  mode = '종합 카테고리';
  const TARGET_CATS = ['22', '23', '25', '26', '27', '28']; // 블로그,코미디,뉴스,노하우,교육,과학
  const after = getPeriodISO(state.period);
  const dur   = document.getElementById('fDuration').value;

  // 카테고리별 병렬 search.list
  const searchResults = await Promise.all(
    TARGET_CATS.map(cId => {
      const p = new URLSearchParams({
        part: 'snippet', type: 'video', maxResults: 50,
        order: 'viewCount', regionCode: region,
        videoDuration: dur, key,
      });
      p.set('videoCategoryId', cId);
      if (after) p.set('publishedAfter', after);
      return fetchJson('https://www.googleapis.com/youtube/v3/search?' + p);
    })
  );

  // 합치기 + 중복 제거
  const seenIds = new Set();
  const allItems = [];
  searchResults.forEach(data => {
    if (data.error) return;
    (data.items||[]).filter(i => i.id?.videoId).forEach(item => {
      if (!seenIds.has(item.id.videoId)) {
        seenIds.add(item.id.videoId);
        allItems.push(item);
      }
    });
  });

  if (allItems.length === 0) { renderEmpty(); updateInfo(mode, 0); return; }

  // videoId / channelId 배치 분할 (50개씩)
  const videoIds   = allItems.map(i => i.id.videoId);
  const channelIds = [...new Set(allItems.map(i => i.snippet.channelId))];
  const chunk = (arr, n) => Array.from({ length: Math.ceil(arr.length/n) }, (_, i) => arr.slice(i*n, i*n+n));

  const [videoResults, channelResults] = await Promise.all([
    Promise.all(chunk(videoIds, 50).map(ids =>
      fetchJson(`https://www.googleapis.com/youtube/v3/videos?part=statistics,snippet&id=${ids.join(',')}&key=${key}`)
    )),
    Promise.all(chunk(channelIds, 50).map(ids =>
      fetchJson(`https://www.googleapis.com/youtube/v3/channels?part=statistics&id=${ids.join(',')}&key=${key}`)
    )),
  ]);

  const vMap  = {};
  videoResults.forEach(d => (d.items||[]).forEach(v => { vMap[v.id] = v; }));
  const chMap = {};
  channelResults.forEach(d => (d.items||[]).forEach(c => { chMap[c.id] = c; }));

