// ── Google Trends ────────────────────────────────
const TRENDS_WORKER = 'https://google-trend.coreawin-ffa.workers.dev/';
const TRENDS_CACHE_KEY = 'yt_trends_cache';

// 현재 캐시 슬롯 (매시 정각·30분 기준 타임스탬프)
function getCacheSlot() {
  const now = new Date();
  const slot = new Date(now);
  slot.setMinutes(now.getMinutes() < 30 ? 0 : 30, 0, 0);
  return slot.getTime();
}

async function loadTrends(forceRefresh = false) {
  const listEl = document.getElementById('trendsList');
  const metaEl = document.getElementById('trendsMeta');

  // 캐시 확인
  if (!forceRefresh) {
    try {
      const cached = JSON.parse(localStorage.getItem(TRENDS_CACHE_KEY) || 'null');
      if (cached && cached.slot === getCacheSlot()) {
        renderTrends(cached.data, cached.fetchedAt);
        return;
      }
    } catch (_) {}
  }

  listEl.innerHTML = '<span class="trends-loading">트렌드 로딩 중...</span>';
  metaEl.textContent = '';

  try {
    const res  = await fetch(TRENDS_WORKER);
    const text = await res.text();

    // RSS XML 파싱
    const parser = new DOMParser();
    const xml    = parser.parseFromString(text, 'text/xml');
    const items  = [...xml.querySelectorAll('item')];

    const trends = items.map(item => ({
      title:   item.querySelector('title')?.textContent?.trim() || '',
      traffic: item.querySelector('ht\\:approx_traffic')?.textContent?.trim() || '',
    })).filter(t => t.title);

    // 캐시 저장
    const cache = { slot: getCacheSlot(), data: trends, fetchedAt: Date.now() };
    localStorage.setItem(TRENDS_CACHE_KEY, JSON.stringify(cache));

    renderTrends(trends, cache.fetchedAt);

  } catch (e) {
    listEl.innerHTML = '<span class="trends-loading" style="color:#555;">트렌드 로딩 실패</span>';
  }
}

function renderTrends(trends, fetchedAt) {
  const listEl = document.getElementById('trendsList');
  const metaEl = document.getElementById('trendsMeta');

  if (!trends || trends.length === 0) {
    listEl.innerHTML = '<span class="trends-loading" style="color:#555;">데이터 없음</span>';
    return;
  }

  listEl.innerHTML = '';
  trends.forEach(t => {
    const chip = document.createElement('button');
    chip.className = 'trend-chip';
    chip.innerHTML = `${esc(t.title)}${t.traffic ? `<span class="traffic">${esc(t.traffic)}</span>` : ''}`;
    chip.addEventListener('click', () => {
      document.getElementById('searchQuery').value = t.title;
      doSearch();
    });
    listEl.appendChild(chip);
  });

  // 캐시 시각 표시
  const d = new Date(fetchedAt);
  const timeStr = `${String(d.getHours()).padStart(2,'0')}:${String(d.getMinutes()).padStart(2,'0')}`;
  const slotStr = d.getMinutes() < 30 ? `${String(d.getHours()).padStart(2,'0')}:00` : `${String(d.getHours()).padStart(2,'0')}:30`;
  metaEl.textContent = `${slotStr} 기준`;
}

