  /march madness|NBA|NFL|EPL|리그|결승|토너먼트|올림픽|월드컵|챔피언십/i,
  /공연|콘서트|컴백|앨범|데뷔|팬미팅|뮤직비디오|음반/,
  /이혼|열애|결혼 발표|임신|출산|열애설|교제/,
  /시상식|드라마 방영|영화 개봉|시즌/,
];

function classifyTrend(title) {
  if (TREND_PATTERNS_SKIP.some(p => p.test(title))) return 'skip';
  if (TREND_PATTERNS_INFO.some(p => p.test(title))) return 'info';
  return 'neutral';
}

// ── Google Trends ────────────────────────────────
const TRENDS_WORKER = 'https://google-trend.coreawin-ffa.workers.dev/';

