const sorted = [...trends].sort((a, b) => {
  const order = { info: 0, neutral: 1, skip: 2 };
  return order[classifyTrend(a.title)] - order[classifyTrend(b.title)];
});

sorted.forEach(t => {
  const type = classifyTrend(t.title);
  const chip = document.createElement('button');
  chip.className = `trend-chip ${type}`;

  const tagLabel = type === 'info' ? '✅정보' : type === 'skip' ? '🔘' : '';
  const tagHtml  = tagLabel ? `<span class="trend-tag ${type}">${tagLabel}</span>` : '';

  chip.innerHTML = `${esc(t.title)}${tagHtml}${t.traffic ? `<span class="traffic">${esc(t.traffic)}</span>` : ''}`;
  chip.title = type === 'info' ? '정보성 키워드' : type === 'skip' ? '연예/스포츠 키워드' : '';
  chip.addEventListener('click', () => {
    document.getElementById('searchQuery').value = t.title;
    doSearch();
